easy.solution:
// TypeScript implementation for Ambient Declarations
interface AmbientDeclarationsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processAmbientDeclarations(item: AmbientDeclarationsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processAmbientDeclarations({ id: 1, title: 'Ambient Declarations', status: 'active' }));

